"use client";
import React from 'react';
import { DollarSign, Info } from 'lucide-react';

const FeeTable = () => {
  const feesData = [
    { id: 1, branch: "Civil Engineering", fee: "3.0" },
    { id: 2, branch: "Electrical & Electronics Engg.", fee: "4.5" },
    { id: 3, branch: "Industrial Engineering & Mgmt", fee: "4.5" },
    { id: 4, branch: "Electronics & Communication Engg.", fee: "6.0" },
    { id: 5, branch: "Mechanical Engineering", fee: "3.5" },
    { id: 6, branch: "Computer Science and Engineering", fee: "10.0", highlighted: true },
    { id: 7, branch: "Chemical Engineering", fee: "2.0" },
    { id: 8, branch: "Bio-Technology", fee: "4.0" },
    { id: 9, branch: "Aerospace Engineering", fee: "4.0" },
    { id: 10, branch: "Artificial Intelligence and Machine Learning", fee: "7.5" },
    { id: 11, branch: "Artificial Intelligence and Data Science", fee: "7.0" },
    { id: 12, branch: "Computer Science and Engineering (Data Science)", fee: "7.5" },
    { id: 13, branch: "CSE (IoT & Cyber Security including Blockchain)", fee: "7.5" },
    { id: 14, branch: "Computer Science & Business Systems", fee: "7.5" },
  ];

  return (
    <section className="py-20 bg-white">
      <div className="max-w-5xl mx-auto px-6">
        
        {/* Header Section */}
        <div className="text-center mb-12">
          <div className="inline-flex items-center gap-2 bg-sky-100 text-sky-600 px-4 py-1.5 rounded-full text-sm font-bold mb-4">
            <DollarSign size={16} />
            Investment for Future
          </div>
          <h2 className="text-3xl md:text-4xl font-black text-slate-900">Fee Structure <span className="text-sky-500">2025-26</span></h2>
          <p className="text-slate-500 mt-3 font-medium">Proposed Fee (₹ in Lakh per annum)</p>
        </div>

        {/* Table Container */}
        <div className="overflow-hidden rounded-3xl border border-sky-100 shadow-2xl shadow-sky-100/50 bg-white">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-sky-500 text-white">
                  <th className="px-6 py-5 font-bold uppercase text-xs tracking-widest">S.No</th>
                  <th className="px-6 py-5 font-bold uppercase text-xs tracking-widest">Name of the Branch</th>
                  <th className="px-6 py-5 font-bold uppercase text-xs tracking-widest text-right">Fee (Lakhs/Year)</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-sky-50">
                {feesData.map((item) => (
                  <tr 
                    key={item.id} 
                    className={`transition-colors hover:bg-sky-50/50 ${item.highlighted ? 'bg-sky-50/80 font-bold' : ''}`}
                  >
                    <td className="px-6 py-4 text-slate-400 font-mono text-sm">{item.id}.</td>
                    <td className="px-6 py-4 text-slate-700">
                      <div className="flex items-center gap-2">
                        {item.branch}
                        {item.highlighted && (
                          <span className="bg-orange-100 text-orange-600 text-[10px] px-2 py-0.5 rounded-full uppercase font-black">Top Choice</span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <span className="text-slate-900 font-black text-lg">₹{item.fee}</span>
                      <span className="text-slate-400 text-xs ml-1">L</span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Note Box */}
        <div className="mt-8 flex items-start gap-4 bg-slate-50 p-6 rounded-2xl border border-slate-200">
          <Info className="text-sky-500 shrink-0" size={24} />
          <div className="text-sm text-slate-600 leading-relaxed">
            <p className="font-bold text-slate-800 mb-1">Important Note:</p>
            The fees mentioned above are proposed for the academic year 2025-26. Final fees may vary based on university norms and category (Management vs. Entrance). Please contact our admission desk at <span className="text-sky-600 font-bold">8707501308</span> for verified details.
          </div>
        </div>

      </div>
    </section>
  );
};

export default FeeTable;